fn cstring_for_ffi(value: &str) -> std::ffi::CString {
    match std::ffi::CString::new(value) {
        Ok(s) => s,
        Err(_) => {
            let bytes: Vec<u8> = value
                .as_bytes()
                .iter()
                .map(|&b| if b == 0 { b'?' } else { b })
                .collect();
            std::ffi::CString::new(bytes).expect("embedded NULs were replaced")
        }
    }
}

